#include <stdio.h>
#include <stdlib.h>
#define MAX_N 15
#define MAX_M 15
#define MAX_K 7

int minCost = INT_MAX;

void dfs(int** board, int** cost, int n, int m, int i, int j, int* visited, int* distinct, int* totalCost, int k) {
    if (i < 0 || i >= n || j < 0 || j >= m || visited[i*m + j] || board[i][j] == -1) return;
    visited[i*m + j] = 1;
    if (board[i][j] > 0) {
        int found = 0;
        for (int x = 0; x < *distinct; x++) {
            if (board[i][j] == distinct[x]) {
                found = 1;
                break;
            }
        }
        if (!found) {
            distinct[*distinct] = board[i][j];
            (*distinct)++;
        }
    }
    (*totalCost) += cost[i][j];
    if (*distinct >= k && *totalCost < minCost) minCost = *totalCost;
    dfs(board, cost, n, m, i-1, j, visited, distinct, totalCost, k);
    dfs(board, cost, n, m, i+1, j, visited, distinct, totalCost, k);
    dfs(board, cost, n, m, i, j-1, visited, distinct, totalCost, k);
    dfs(board, cost, n, m, i, j+1, visited, distinct, totalCost, k);
    visited[i*m + j] = 0;
    (*totalCost) -= cost[i][j];
    if (board[i][j] > 0) {
        for (int x = 0; x < *distinct; x++) {
            if (board[i][j] == distinct[x]) {
                for (int y = x; y < *distinct - 1; y++) {
                    distinct[y] = distinct[y+1];
                }
                (*distinct)--;
                break;
            }
        }
    }
}

int main() {
    int n, m, k;
    scanf("%d %d %d", &n, &m, &k);
    int** board = (int**)malloc(n*sizeof(int*));
    int** cost = (int**)malloc(n*sizeof(int*));
    for (int i = 0; i < n; i++) {
        board[i] = (int*)malloc(m*sizeof(int));
        cost[i] = (int*)malloc(m*sizeof(int));
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &board[i][j]);
        }
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &cost[i][j]);
        }
    }
    int* visited = (int*)malloc(n*m*sizeof(int));
    int* distinct = (int*)malloc(MAX_K*sizeof(int));
    int totalCost = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (!visited[i*m + j] && board[i][j] != -1) {
                dfs(board, cost, n, m, i, j, visited, distinct, &totalCost, k);
            }
        }
    }
    if (minCost == INT_MAX) printf("-1\n");
    else printf("%d\n", minCost);
    return 0;
}

