#include <iostream>
#include <vector>
using namespace std;
#define MAX_N 15
#define MAX_M 15
#define MAX_K 7

int minCost = INT_MAX;

void dfs(vector<vector<int>>& board, vector<vector<int>>& cost, int n, int m, int i, int j, vector<vector<bool>>& visited, vector<int>& distinct, int& totalCost, int k) {
    if (i < 0 || i >= n || j < 0 || j >= m || visited[i][j] || board[i][j] == -1) return;
    visited[i][j] = true;
    if (board[i][j] > 0) {
        bool found = false;
        for (int x = 0; x < distinct.size(); x++) {
            if (board[i][j] == distinct[x]) {
                found = true;
                break;
            }
        }
        if (!found) {
            distinct.push_back(board[i][j]);
        }
    }
    totalCost += cost[i][j];
    if (distinct.size() >= k && totalCost < minCost) minCost = totalCost;
    dfs(board, cost, n, m, i-1, j, visited, distinct, totalCost, k);
    dfs(board, cost, n, m, i+1, j, visited, distinct, totalCost, k);
    dfs(board, cost, n, m, i, j-1, visited, distinct, totalCost, k);
    dfs(board, cost, n, m, i, j+1, visited, distinct, totalCost, k);
    visited[i][j] = false;
    totalCost -= cost[i][j];
    if (board[i][j] > 0) {
        for (int x = 0; x < distinct.size(); x++) {
            if (board[i][j] == distinct[x]) {
                distinct.erase(distinct.begin() + x);
                break;
            }
        }
    }
}

int main() {
    int n, m, k;
    cin >> n >> m >> k;
    vector<vector<int>> board(n, vector<int>(m));
    vector<vector<int>> cost(n, vector<int>(m));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            cin >> board[i][j];
        }
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            cin >> cost[i][j];
        }
    }
    vector<vector<bool>> visited(n, vector<bool>(m, false));
    vector<int> distinct;
    int totalCost = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (!visited[i][j] && board[i][j] != -1) {
                dfs(board, cost, n, m, i, j, visited, distinct, totalCost, k);
            }
        }
    }
    if (minCost == INT_MAX) cout << -1 << endl;
    else cout << minCost << endl;
    return 0;
}

