import java.util.Scanner;
public class Main {
    static int minCost = Integer.MAX_VALUE;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();
        int k = sc.nextInt();
        int[][] board = new int[n][m];
        int[][] cost = new int[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                board[i][j] = sc.nextInt();
            }
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                cost[i][j] = sc.nextInt();
            }
        }
        boolean[][] visited = new boolean[n][m];
        dfs(board, cost, n, m, 0, 0, visited, new int[7], 0, k);
        if (minCost == Integer.MAX_VALUE) System.out.println(-1);
        else System.out.println(minCost);
    }
    public static void dfs(int[][] board, int[][] cost, int n, int m, int i, int j, boolean[][] visited, int[] distinct, int index, int k) {
        if (i < 0 || i >= n || j < 0 || j >= m || visited[i][j] || board[i][j] == -1) return;
        visited[i][j] = true;
        if (board[i][j] > 0) {
            boolean found = false;
            for (int x = 0; x < index; x++) {
                if (board[i][j] == distinct[x]) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                distinct[index] = board[i][j];
            }
        }
        int totalCost = 0;
        for (int x = 0; x < n; x++) {
            for (int y = 0; y < m; y++) {
                if (visited[x][y]) totalCost += cost[x][y];
            }
        }
        if (index >= k && totalCost < minCost) minCost = totalCost;
        dfs(board, cost, n, m, i-1, j, visited, distinct, index, k);
        dfs(board, cost, n, m, i+1, j, visited, distinct, index, k);
        dfs(board, cost, n, m, i, j-1, visited, distinct, index, k);
        dfs(board, cost, n, m, i, j+1, visited, distinct, index, k);
        visited[i][j] = false;
    }
}

